#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the graph
    vector<vector<long long>> graph(c + 1);
    for (const auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    vector<long long> parent(c + 1);
    vector<long long> min_id(c + 1); // Minimum id in the set
    vector<bool> is_online(c + 1, true);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        min_id[i] = i;
    }

    // Find function with path compression
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    // Union function
    auto union_sets = [&](long long x, long long y) -> void {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x != root_y) {
            parent[root_y] = root_x;
            min_id[root_x] = min(min_id[root_x], min_id[root_y]);
        }
    };

    // Build the DSU structure based on connections
    for (long long i = 1; i <= c; ++i) {
        for (size_t j = 0; j < graph[i].size(); ++j) {
            long long neighbor = graph[i][j];
            if (i < neighbor) {
                union_sets(i, neighbor);
            }
        }
    }

    vector<long long> result;

    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];

        if (type == 1) {
            if (is_online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                long long min_online_id = min_id[root];
                // Check if there are any online nodes in this set
                bool has_online = false;
                for (long long i = 1; i <= c; ++i) {
                    if (find(i) == root && is_online[i]) {
                        has_online = true;
                        break;
                    }
                }
                if (has_online) {
                    result.push_back(min_online_id);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            is_online[x] = false;
        }
    }

    return result;
}

