        for (size_t j = 0; j < graph[i].size(); ++j) {
            long long neighbor = graph[i][j];
            if (i < neighbor) {
                union_sets(i, neighbor);
            }
        }
    }

    vector<long long> result;

    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];

        if (type == 1) {
            if (is_online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                long long min_online_id = min_id[root];
                // Check if there are any online nodes in this set
                bool has_online = false;
                for (long long i = 1; i <= c; ++i) {
                    if (find(i) == root && is_online[i]) {
                        has_online = true;
                        break;
                    }
                }
                if (has_online) {
                    result.push_back(min_online_id);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            is_online[x] = false;
        }
    }

    return result;
